#include <stdio.h>
#include <string.h>
#include <ctype.h>
#include <stdlib.h>

int isVowel(char c){
    c = tolower((unsigned char)c);
    return c=='a'||c=='e'||c=='i'||c=='o'||c=='u';
}

typedef struct Node{char *word; int cnt; struct Node *next;} Node;

int main(){
    int T; if(scanf("%d",&T)!=1) return 0; getchar(); // consume newline
    char line[2005];
    for(int tc=0; tc<T; ++tc){
        if(!fgets(line,sizeof(line),stdin)) line[0]='\0';
        size_t len=strlen(line);
        if(len && line[len-1]=='\n') line[len-1]='\0';
        // ordered list of keys
        Node *head=NULL, *tail=NULL;
        // map for fast lookup (simple linear search because constraints are tiny)
        Node *search=NULL;
        char *token = strtok(line, " ");
        while(token){
            int cnt=0; for(char *p=token; *p; ++p) if(isVowel(*p)) ++cnt;
            // check if already exists
            Node *prev=NULL, *cur=head;
            while(cur && strcmp(cur->word, token)!=0){ prev=cur; cur=cur->next; }
            if(cur){ // exists: update count and move to tail
                cur->cnt = cnt;
                if(cur!=tail){
                    // unlink cur
                    if(prev) prev->next = cur->next; else head = cur->next;
                    // append at tail
                    tail->next = cur; cur->next = NULL; tail = cur;
                }
            } else {
                Node *node = malloc(sizeof(Node));
                node->word = strdup(token);
                node->cnt = cnt;
                node->next = NULL;
                if(!head) head = tail = node; else { tail->next = node; tail = node; }
            }
            token = strtok(NULL, " ");
        }
        // print dictionary
        printf("{");
        for(Node *p=head; p; p=p->next){
            printf("'%s': %d", p->word, p->cnt);
            if(p->next) printf(", ");
        }
        printf("}\n");
        // free
        for(Node *p=head; p;){ Node *n=p->next; free(p->word); free(p); p=n; }
    }
    return 0;
}

