import sys

def vowel_count(word):
    return sum(1 for ch in word if ch.lower() in 'aeiou')

def process(sentence):
    order = []
    mp = {}
    for w in sentence.split():
        cnt = vowel_count(w)
        if w in mp:
            order.remove(w)
        order.append(w)
        mp[w] = cnt
    return '{' + ', '.join(f"'{k}': {mp[k]}" for k in order) + '}'

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    for i in range(1, T+1):
        sentence = data[i] if i < len(data) else ''
        print(process(sentence))

if __name__ == '__main__':
    main()

